/**
 * Weight bracket classifier for parcels.
 *
 * Brackets:
 *   standard : 0 < weight < 10 kg
 *   heavy    : 10 <= weight < 50 kg
 *   freight  : 50 <= weight <= 1000 kg
 *
 * Throws a validation error for weight <= 0 or weight > 1000.
 */

export class WeightValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "WeightValidationError";
  }
}

export function classifyWeight(weight: number): "standard" | "heavy" | "freight" {
  if (weight <= 0) {
    throw new WeightValidationError(
      `Invalid weight: ${weight} kg. Weight must be greater than 0.`
    );
  }

  if (weight > 1000) {
    throw new WeightValidationError(
      `Invalid weight: ${weight} kg. Weight must not exceed 1000 kg.`
    );
  }

  if (weight < 10) {
    return "standard";
  }

  if (weight < 50) {
    return "heavy";
  }

  return "freight";
}

