import { classifyWeight, WeightValidationError } from "./classifyWeight";

describe("classifyWeight", () => {
  // AC1: 5 kg → "standard"
  it("AC1: returns 'standard' for a weight of 5 kg", () => {
    expect(classifyWeight(5)).toBe("standard");
  });

  // AC2: 10 kg → "heavy" (inclusive lower boundary)
  it("AC2: returns 'heavy' for a weight of 10 kg (inclusive boundary)", () => {
    expect(classifyWeight(10)).toBe("heavy");
  });

  // AC3: 50 kg → "freight" (inclusive lower boundary)
  it("AC3: returns 'freight' for a weight of 50 kg (inclusive boundary)", () => {
    expect(classifyWeight(50)).toBe("freight");
  });

  // AC4: 0 kg → validation error
  it("AC4: throws WeightValidationError for a weight of 0 kg", () => {
    expect(() => classifyWeight(0)).toThrow(WeightValidationError);
    expect(() => classifyWeight(0)).toThrow("Invalid weight: 0 kg");
  });

  // AC5: 1001 kg → validation error
  it("AC5: throws WeightValidationError for a weight of 1001 kg", () => {
    expect(() => classifyWeight(1001)).toThrow(WeightValidationError);
    expect(() => classifyWeight(1001)).toThrow("Invalid weight: 1001 kg");
  });

  // Boundary and interior coverage (additional robustness)
  it("returns 'standard' for weight just below the heavy threshold (9.99 kg)", () => {
    expect(classifyWeight(9.99)).toBe("standard");
  });

  it("returns 'heavy' for weight just below the freight threshold (49.99 kg)", () => {
    expect(classifyWeight(49.99)).toBe("heavy");
  });

  it("returns 'freight' for the maximum valid weight (1000 kg)", () => {
    expect(classifyWeight(1000)).toBe("freight");
  });

  it("returns 'freight' for a mid-range freight weight (200 kg)", () => {
    expect(classifyWeight(200)).toBe("freight");
  });

  it("throws WeightValidationError for negative weight", () => {
    expect(() => classifyWeight(-1)).toThrow(WeightValidationError);
  });

  it("throws for weight of exactly 0 with correct error name", () => {
    try {
      classifyWeight(0);
      fail("Expected WeightValidationError to be thrown");
    } catch (err) {
      expect(err).toBeInstanceOf(WeightValidationError);
      expect((err as WeightValidationError).name).toBe("WeightValidationError");
    }
  });
});

